#!/bin/bash
c0_hex=$(printf "​"|xxd -p|tr -d '\n');c1_hex=$(printf "⁠"|xxd -p|tr -d '\n');hex=$(xxd -p -c 1000000 tmf.txt|tr -d '\n');i=0;n=0;l=${#hex};while [ $i -lt $l ];do if [ "${hex:$i:${#c0_hex}}" == "$c0_hex" ]||[ "${hex:$i:${#c1_hex}}" == "$c1_hex" ];then b="";p=$i;while [ $i -lt $l ]&&([ "${hex:$i:${#c0_hex}}" == "$c0_hex" ]||[ "${hex:$i:${#c1_hex}}" == "$c1_hex" ]);do [ "${hex:$i:${#c1_hex}}" == "$c1_hex" ]&&b+="1"||b+="0";i=$((i+${#c0_hex}));done;by="";for((j=0;j<${#b};j+=8));do bt="${b:$j:8}";[ ${#bt} -ne 8 ]&&break;bv=$((2#$bt));by+=$(printf "%02x" $bv);done;t=$(echo "$by"|xxd -r -p 2>/dev/null);printf "\e[31m[%x]\e[0m %s\n" $((p/2)) "$t";((n++));else i=$((i+2));fi;done;[ $n -eq 0 ]&&echo "Nothing found"
